async (page) => {
  // Intercept tier API to return "pro" 
  await page.route('**/api/auth/tier', route => {
    route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ tier: 'pro' })
    });
  });

  // Clear localStorage and reload
  await page.evaluate(() => localStorage.clear());
  await page.goto('http://localhost:5173/terminal');

  // Remove upgrade gate
  await page.evaluate(() => document.querySelector('#upgrade-gate')?.remove());

  // Sign in via Firebase
  await page.evaluate(async () => {
    await firebase.auth().signInWithEmailAndPassword('dev-max+testpdlr37ax@gmail.com', 'playwright');
  });

  // Wait for tier fetch to complete
  await page.waitForTimeout(5000);

  // Check results
  const result = await page.evaluate(() => {
    const overlay = document.querySelector('#onboarding-overlay');
    const tierBadge = document.querySelector('#tier-badge');
    const onboardingDone = localStorage.getItem('instnews_onboarding_done');
    return {
      overlayExists: !!overlay,
      tierBadge: tierBadge?.textContent?.trim(),
      onboardingDone
    };
  });

  return result;
}

async (page) => {
  // Intercept tier API to return "pro"
  await page.route('**/api/auth/tier', route => {
    route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ tier: 'pro' })
    });
  });

  // Clear localStorage and reload
  await page.evaluate(() => localStorage.clear());
  await page.goto('http://localhost:5173/terminal');

  // Wait for Firebase to initialize
  await page.waitForFunction(() => typeof firebase !== 'undefined' && firebase.apps && firebase.apps.length > 0, { timeout: 10000 });

  // Remove upgrade gate
  await page.evaluate(() => document.querySelector('#upgrade-gate')?.remove());

  // Sign in via Firebase
  await page.evaluate(async () => {
    const auth = firebase.auth();
    await auth.signInWithEmailAndPassword('dev-max+testpdlr37ax@gmail.com', 'playwright');
  });

  // Wait for tier fetch + onboarding logic
  await page.waitForTimeout(5000);

  // Check results
  const result = await page.evaluate(() => {
    const overlay = document.querySelector('#onboarding-overlay');
    const tierBadge = document.querySelector('#tier-badge');
    const onboardingDone = localStorage.getItem('instnews_onboarding_done');
    const colVis = localStorage.getItem('instnews_column_visibility');
    return {
      overlayExists: !!overlay,
      tierBadge: tierBadge?.textContent?.trim(),
      onboardingDone,
      hasColConfig: !!colVis
    };
  });

  return result;
}

